// ─── COTIZAR JS (PDF con imágenes en base64) ───

let selectedProductId = 'rosa-pastel';
let selectedPrice = 45;

function selectProduct(el, productId, price) {
  document.querySelectorAll('.product-card').forEach(c => c.classList.remove('active'));
  el.classList.add('active');
  selectedProductId = productId;
  selectedPrice = price;
}

// Productos con las imágenes ya incrustadas como data URL
const productsMap = {
  'rosa-pastel': {
    name: 'Rosa Pastel',
    img: 'data:image/png;base64,',       // ← Pega aquí el data URL
    price: 45,
    desc: 'Rosas pastel y lisianthus en tonos suaves. Elegancia romántica.'
  },
  'promesa-flores': {
    name: 'Promesa de Flores',
    img: 'data:image/png;base64,',     // ← Pega aquí el data URL
    price: 55,
    desc: 'Rosas pastel y lisianthus violetas. Una promesa hecha ramo.'
  },
  'arreglo-morado': {
    name: 'Encanto Violeta',
    img: 'data:image/png;base64,',     // ← Pega aquí el data URL
    price: 65,
    desc: 'Rosas pastel y lisianthus morados en base artesanal.'
  }
};

async function generateAndDownloadPDF() {
  const name  = document.getElementById('c-name').value.trim();
  const phone = document.getElementById('c-phone').value.trim();

  if (!name)  { alert('Por favor ingresa tu nombre.'); return; }
  if (!phone) { alert('Por favor ingresa tu teléfono.'); return; }

  const email  = document.getElementById('c-email').value.trim();
  const date   = document.getElementById('c-date').value;
  const guests = document.getElementById('c-guests').value.trim();
  const venue  = document.getElementById('c-venue').value.trim();
  const budget = document.getElementById('c-budget').value;
  const vision = document.getElementById('c-vision').value.trim();

  const product = productsMap[selectedProductId];

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF('p', 'mm', 'a4');

  const backgroundColor = '#FFF9F5';
  const primaryColor = '#A87B7B';
  const accentColor = '#D4A5A5';
  const textColor = '#4A3B3B';
  const lightLine = '#E8D5D5';

  doc.setFillColor(backgroundColor);
  doc.rect(0, 0, 210, 297, 'F');

  doc.setFont('Times', 'italic');
  doc.setFontSize(26);
  doc.setTextColor(primaryColor);
  doc.text('La Casa de las Flores', 105, 25, { align: 'center' });

  doc.setDrawColor(accentColor);
  doc.setLineWidth(0.7);
  doc.line(60, 30, 150, 30);

  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(11);
  doc.setTextColor(textColor);
  doc.text('Cotización personalizada de evento', 105, 37, { align: 'center' });

  // ─── Usamos directamente el data URL del producto ───
  const imgWidth = 70;
  const imgHeight = 70;
  const imgX = (210 - imgWidth) / 2;
  const imgY = 43;

  doc.setFillColor('#FDF6F0');
  doc.roundedRect(imgX - 2, imgY - 2, imgWidth + 4, imgHeight + 4, 5, 5, 'F');
  doc.addImage(product.img, 'PNG', imgX, imgY, imgWidth, imgHeight);  // product.img ya es un data URL

  doc.setFont('Times', 'bold');
  doc.setFontSize(18);
  doc.setTextColor(primaryColor);
  doc.text(product.name, 105, 120, { align: 'center' });

  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(12);
  doc.setTextColor(textColor);
  doc.text(product.desc, 105, 128, { align: 'center' });

  doc.setFont('Helvetica', 'bold');
  doc.setFontSize(16);
  doc.setTextColor(primaryColor);
  doc.text(`Desde $${product.price.toFixed(2)}`, 105, 138, { align: 'center' });

  doc.setDrawColor(lightLine);
  doc.setLineWidth(0.5);
  doc.line(25, 145, 185, 145);

  const startY = 152;
  doc.setFont('Times', 'italic');
  doc.setFontSize(14);
  doc.setTextColor(primaryColor);
  doc.text('Datos de tu evento', 25, startY);

  const details = [
    { label: 'Nombre', value: name },
    { label: 'Teléfono', value: phone },
    { label: 'Correo', value: email || '—' },
    { label: 'Fecha del evento', value: formatDate(date) || '—' },
    { label: 'Invitados', value: guests || '—' },
    { label: 'Lugar', value: venue || '—' },
    { label: 'Presupuesto estimado', value: budget },
    { label: 'Visión / Notas', value: vision || '—' }
  ];

  let yPos = startY + 7;
  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(10);
  doc.setTextColor(textColor);

  details.forEach(item => {
    doc.setTextColor('#6B5B5B');
    doc.setFont('Helvetica', 'bold');
    doc.text(`${item.label}:`, 30, yPos);
    doc.setTextColor(textColor);
    doc.setFont('Helvetica', 'normal');
    doc.text(item.value, 72, yPos);
    yPos += 7;
  });

  yPos += 2;
  doc.setDrawColor(lightLine);
  doc.line(25, yPos, 185, yPos);

  const footerY = yPos + 10;
  doc.setFont('Times', 'italic');
  doc.setFontSize(12);
  doc.setTextColor(primaryColor);
  doc.text('Gracias por confiar en nosotros', 105, footerY, { align: 'center' });
  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(9);
  doc.setTextColor('#6B5B5B');
  doc.text('Válido por 7 días · La Casa de las Flores · San Salvador', 105, footerY + 6, { align: 'center' });
  doc.text('WhatsApp: +503 7048-3939 | @lacasadelasflores_sv', 105, footerY + 11, { align: 'center' });

  doc.save('cotizacion_lacasadelasflores.pdf');
  showSuccessMessage();
}

function formatDate(dateStr) {
  if (!dateStr) return '';
  const [y, m, d] = dateStr.split('-');
  const months = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
  return `${parseInt(d)} de ${months[parseInt(m)-1]} de ${y}`;
}

function showSuccessMessage() {
  const btn = document.querySelector('.btn-submit');
  const note = document.querySelector('.form-note');
  const successMsg = document.getElementById('success-msg');

  if (btn) btn.style.display = 'none';
  if (note) note.style.display = 'none';
  if (successMsg) {
    successMsg.style.display = 'block';
    successMsg.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }
}

function sendWhatsApp() {
  const product = productsMap[selectedProductId];

  const name   = document.getElementById('c-name').value.trim();
  const phone  = document.getElementById('c-phone').value.trim();
  const email  = document.getElementById('c-email').value.trim();
  const date   = document.getElementById('c-date').value;
  const guests = document.getElementById('c-guests').value.trim();
  const venue  = document.getElementById('c-venue').value.trim();
  const budget = document.getElementById('c-budget').value;
  const vision = document.getElementById('c-vision').value.trim();

  const whatsappPhone = '50370483939';
  let msg = `🌸 *COTIZACIÓN DE EVENTO - La Casa de las Flores*\n\n`;
  msg += `*Arreglo elegido:* ${product.name} (Desde $${product.price.toFixed(2)})\n`;
  msg += `*Nombre:* ${name}\n`;
  msg += `*Teléfono:* ${phone}\n`;
  if (email)  msg += `*Correo:* ${email}\n`;
  if (date)   msg += `*Fecha del evento:* ${formatDate(date)}\n`;
  if (guests) msg += `*Invitados:* ${guests}\n`;
  if (venue)  msg += `*Lugar:* ${venue}\n`;
  msg += `*Presupuesto:* ${budget}\n`;
  if (vision) msg += `\n*Visión / Notas:*\n${vision}\n`;
  msg += `\n📄 Ya descargué el PDF de mi cotización. Quedo atento(a) a sus comentarios.`;

  const url = `https://wa.me/${whatsappPhone}?text=${encodeURIComponent(msg)}`;
  window.open(url, '_blank');
}